        const matchEnd = matchIndex + lowerQuery.length;
        segments.push(<mark key={key++}>{text.slice(matchIndex, matchEnd)}</mark>);

        start = matchEnd;
        matchIndex = lowerText.indexOf(lowerQuery, start);
    }

